arguments.file_text:
namespace sv_e312442ef09844a4a713786abc45d239.Services;

public class WarehouseState
{
    public string SelectedWarehouseId { get; private set; } = "WH-001";

    public string SelectedWarehouseName =>
        Warehouses.TryGetValue(SelectedWarehouseId, out var name) ? name : SelectedWarehouseId;

    public static readonly Dictionary<string, string> Warehouses = new()
    {
        ["WH-001"] = "Warehouse A — Main Distribution",
        ["WH-002"] = "Warehouse B — East Regional",
        ["WH-003"] = "Warehouse C — West Regional",
        ["WH-004"] = "Warehouse D — Cold Storage",
    };

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId)
            return;

        SelectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_e312442ef09844a4a713786abc45d239.Services;

public class InventoryAlertService : IAsyncDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _activePollConsumers;

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Fired whenever LowStockCount changes. Handlers MUST wrap
    /// StateHasChanged in InvokeAsync because this fires from a
    /// background timer thread.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
