arguments.file_text:
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label for="warehouseDropdown" class="form-label text-white mb-1 small">Current Warehouse</label>
    <select id="warehouseDropdown"
            class="form-select form-select-sm"
            value="@WarehouseState.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.Warehouses)
        {
            <option value="@wh.Key">@wh.Value</option>
        }
    </select>
</div>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _handler;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            WarehouseState.SetWarehouse(newId);
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= _handler;
    }
}

::deep .warehouse-selector {
    padding: 0.5rem 1rem;
    border-bottom: 1px solid rgba(255,255,255,0.15);
}

::deep .warehouse-selector .form-select {
    background-color: rgba(255,255,255,0.15);
    color: white;
    border-color: rgba(255,255,255,0.25);
    font-size: 0.8rem;
}

::deep .warehouse-selector .form-select option {
    background-color: #1a1a2e;
    color: white;
}

@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
