@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertCountChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Current Warehouse</h5>
                <p class="display-6">@WarehouseState.SelectedWarehouseName</p>
                <span class="badge bg-info">@WarehouseState.SelectedWarehouseId</span>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card @(AlertService.LowStockCount > 5 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Low Stock Alerts</h5>
                <p class="display-3 @(AlertService.LowStockCount > 5 ? "text-danger" : "text-success")">
                    @AlertService.LowStockCount
                </p>
                <small class="text-muted">items below minimum level</small>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title text-muted">Polling Status</h5>
                <p class="display-6 text-success">● Active</p>
                <small class="text-muted">refreshing every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        AlertService.StartPolling();
    }

    public void Dispose()
    {
        AlertService.StopPolling();
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

